class AgentState(Enum): IDLE = "idle" LISTENING = "listening" PROCESSING = "processing" SPEAKING = "speaking"
@dataclass class VoiceAgentConfig: system_prompt: str voice: str = "nova" stt_model: str = "whisper-1" llm_model: str = "gpt-4o" tts_model: str = "tts-1" max_response_tokens: int = 200 vad_threshold: float = 0.02 silence_timeout: float = 1.0 max_turns: int = 50
async def handle_audio(self, audio_data: bytes) -> Optional[bytes]: if self.state == AgentState.SPEAKING: return None # barge-in prevention if self.turn_count >= self.config.max_turns: return await self._speak("I need to end our conversation now.") ...

# Only call LLM a second time if there were tool calls
if message.tool_calls:
    self.conversation_history.append(message)
    for tool_call in message.tool_calls:
        func_name = tool_call.function.name
        args = json.loads(tool_call.function.arguments)
        if func_name in self.tool_functions:
            result = self.tool_functions[func_name](**args)
        else:
            result = {"error": f"Unknown function: {func_name}"}
        self.conversation_history.append({
            "role": "tool", "tool_call_id": tool_call.id,
            "content": json.dumps(result)
        })
    # Second LLM call ONLY here — not unconditionally
    final = self.client.chat.completions.create(
        model=self.config.llm_model,
        messages=self.conversation_history,
        max_tokens=self.config.max_response_tokens
    )
    message = final.choices[0].message
